const body = $input.first().json.body || $input.first().json;
const videos = body.videos || [];
const ffmpegCmds = body.ffmpeg_commands || [];
const productId = body.product_id;
const storeUrls = body.store_urls || {};
const brand = body.brand || {};

// Separate avatar script from text-overlay videos
const avatarScript = videos.find(v => v.video_id === 'ugc_avatar_script');
const textVideos = videos.filter(v => v.video_id !== 'ugc_avatar_script');

return [{ json: {
  product_id: productId,
  text_videos: textVideos,
  avatar_script: avatarScript || null,
  ffmpeg_commands: ffmpegCmds,
  store_urls: storeUrls,
  brand,
  primary_color: brand.colors?.primary || '#1B2A4A',
  accent_color: brand.colors?.accent || '#C9A84C',
  has_avatar: !!avatarScript,
  _received_at: new Date().toISOString()
}}];

// Build FFmpeg text-overlay commands for each video
const data = $input.first().json;
const videos = data.text_videos || [];
const productId = data.product_id;
const primary = (data.primary_color || '#1B2A4A').replace('#', '0x');
const accent = (data.accent_color || '#C9A84C').replace('#', '0x');
const white = '0xFFFFFF';
const workDir = `/tmp/videos_${productId}`;

const commands = [];

for (const video of videos) {
  const scenes = video.scenes || [];
  const duration = video.duration_seconds || 15;
  const outputFile = `${workDir}/${video.video_id}.mp4`;

  if (video.style === 'text_overlay_product_reveal' || video.style === 'tips_text_overlay') {
    // Build drawtext filter chain
    const textFilters = scenes.map((scene, i) => {
      const text = (scene.text_overlay || '').replace(/'/g, "'\\''").substring(0, 60);
      const y = scene.position === 'bottom' ? 'h-150' : scene.position === 'top' ? '100' : '(h-text_h)/2';
      const fontSize = scene.fontsize || 56;
      const fadeIn = `alpha='if(lt(t,${scene.timestamp_start}),0,if(lt(t,${scene.timestamp_start+0.5}),(t-${scene.timestamp_start})/0.5,if(lt(t,${scene.timestamp_end-0.3}),1,max(0,(${scene.timestamp_end}-t)/0.3))))'`;
      return `drawtext=text='${text}':fontsize=${fontSize}:fontcolor=${white}:x=(w-text_w)/2:y=${y}:enable='between(t,${scene.timestamp_start},${scene.timestamp_end})':${fadeIn}:box=1:boxcolor=${primary}@0.5:boxborderw=20`;
    }).join(',');

    const cmd = `ffmpeg -y -loop 1 -i ${workDir}/bg_navy.jpg -vf "scale=1080:1920:force_original_aspect_ratio=decrease,pad=1080:1920:(ow-iw)/2:(oh-ih)/2:${primary},drawbox=x=0:y=0:w=1080:h=8:color=${accent}:t=fill,${textFilters}" -c:v libx264 -t ${duration} -r 30 -pix_fmt yuv420p -crf 23 ${outputFile}`;

    commands.push({
      video_id: video.video_id,
      platform: video.platform,
      command: cmd,
      output_file: outputFile,
      duration: duration,
      caption: video.caption,
      hashtags: video.hashtags,
      title: video.title || null,
      description: video.description || null
    });

  } else if (video.style === 'product_walkthrough_text') {
    // YouTube Shorts — slightly longer, more text
    const cmd = `ffmpeg -y -loop 1 -i ${workDir}/bg_navy.jpg -vf "scale=1080:1920:force_original_aspect_ratio=decrease,pad=1080:1920:(ow-iw)/2:(oh-ih)/2:${primary},drawbox=x=0:y=0:w=1080:h=8:color=${accent}:t=fill,drawtext=text='${(video.hook_words || 'WATCH THIS').replace(/'/g, "'\\''").substring(0,30)}':fontsize=72:fontcolor=${white}:x=(w-text_w)/2:y=(h-text_h)/2:enable='between(t,0,5)',drawtext=text='Link in bio':fontsize=48:fontcolor=${accent}:x=(w-text_w)/2:y=h-200:enable='between(t,${duration-5},${duration})'" -c:v libx264 -t ${duration} -r 30 -pix_fmt yuv420p -crf 23 ${outputFile}`;

    commands.push({
      video_id: video.video_id,
      platform: video.platform,
      command: cmd,
      output_file: outputFile,
      duration: duration,
      title: video.title,
      description: video.description,
      tags: video.tags
    });
  }
}

// Also add product zoom animation
commands.push({
  video_id: 'product_zoom_pan',
  platform: 'all',
  command: `ffmpeg -y -loop 1 -i ${workDir}/bg_navy.jpg -vf "scale=1080:1920:force_original_aspect_ratio=increase,crop=1080:1920,zoompan=z='min(zoom+0.0015,1.25)':x='iw/2-(iw/zoom/2)':y='ih/2-(ih/zoom/2)':d=240:s=1080x1920,setsar=1" -c:v libx264 -t 8 -r 30 -pix_fmt yuv420p ${workDir}/product_zoom.mp4`,
  output_file: `${workDir}/product_zoom.mp4`,
  duration: 8,
  description: 'Product zoom animation for stories/ads'
});

return commands.map(cmd => ({ json: { ...data, video_job: cmd } }));

// Parse render result
const result = $input.first().json;
const stdout = result.stdout || '';
const success = stdout.includes('VIDEO_OK');
const parts = stdout.split('|');

return [{ json: {
  ...result,
  video_rendered: success,
  video_path: success ? parts[1] : null,
  video_size: success ? parts[2] : null,
  video_id: result.video_job?.video_id,
  platform: result.video_job?.platform,
  caption: result.video_job?.caption,
  hashtags: result.video_job?.hashtags,
  title: result.video_job?.title,
  description: result.video_job?.description
}}];

