// Collect all rendered videos and avatar
const allVideos = $input.all();
const renderedVideos = [];

for (const item of allVideos) {
  const data = item.json;
  if (data.video_rendered && data.video_path) {
    renderedVideos.push({
      video_id: data.video_id,
      platform: data.platform,
      file_path: data.video_path,
      file_size: data.video_size,
      caption: data.caption,
      hashtags: data.hashtags,
      title: data.title,
      description: data.description,
      type: 'text_overlay'
    });
  }
  // Check for HeyGen avatar result
  if (data.data?.video_url) {
    renderedVideos.push({
      video_id: 'ugc_avatar',
      platform: 'all',
      video_url: data.data.video_url,
      type: 'avatar',
      disclosure: 'AI-generated spokesperson | Not a real person'
    });
  }
}

return [{ json: {
  product_id: $('⚙️ Prep Video Jobs').first().json.product_id,
  rendered_videos: renderedVideos,
  total_rendered: renderedVideos.length,
  has_avatar: renderedVideos.some(v => v.type === 'avatar'),
  store_urls: $('⚙️ Prep Video Jobs').first().json.store_urls,
  _completed_at: new Date().toISOString()
}}];
